var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로…… 정녕 너란 말이냐?","JPN":"マエストロ……本当に貴様なのか？","ENG":"Maestra... Could it really be you?","TWN":"你真的……是指揮家嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지난날에 대한 속죄 따윈 없이! 인간의 허물을 쓰고 숨어 지냈단 말이냐!","JPN":"過ぎし日への償いすら無く！　人間の皮を被り隠れていたというのか！","ENG":"No atonement for your sins, instead you’ve been hiding under the guise of a human!","TWN":"你不但沒有為以前的事贖罪！甚至還偽裝成人的樣子躲起來嗎！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러니까 몇 번이나 아니라고 했잖아!","JPN":"だから何度も違うって言ってるでしょう！","ENG":"I told you no several times!","TWN":"我不是一直跟你說我不是嗎！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"용병 씨! 뭔가 꿍꿍이를 꾸미고 있는 거 아니었어?!","JPN":"傭兵さん！　なんか策があるんじゃなかったの！？","ENG":"Ms. Mercenary! Don’t you have anything else up your sleeve?","TWN":"傭兵小姐！你不是有在打什麼算盤嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래, 슬슬 끝나지 않았으려나?","JPN":"そうよ、そろそろできたんじゃないかしら？","ENG":"It shall be ready soon.","TWN":"是啊，但好像還需要點時間？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"저건…… 알렉스 부전대장인가? 살아 있었어?","JPN":"あれは……アレックス副戦隊長？　生きていたのか？","ENG":"Is that... Deputy Commander Alex? She’s still alive?","TWN":"那是……雅蕾克絲副戰隊長嗎？她還活著？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그런데 저 여자가 어째서 마에스트로를……?","JPN":"ところで、どうしてあの女がマエストロを……？","ENG":"But why is she protecting Maestra...?","TWN":"她為什麼跟指揮家……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……! 역시 나리네 친구야! 굉장한데!","JPN":"へ、へへ……！　やっぱり旦那のお仲間だ！　すげぇな！","ENG":"Heh heh...! That friend of yours truly is amazing!","TWN":"嘿嘿嘿……！真不愧是姊的朋友！超威的！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그래. 하지만 어째서인지 반응이 없어.","JPN":"そうだな。でもなぜか反応がない。","ENG":"Sure. But there’s still no response.","TWN":"嗯嗯，不過為什麼沒反應？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤, 반응이 없다니 무슨 소리야?","JPN":"へ、へへ。反応がないってどういうことだ？","ENG":"Heh, no response? What do you mean?","TWN":"嘿嘿嘿，沒反應是什麼意思？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아무튼 죽이러 가면 되지? 응? 우리 아빠의 원수……!","JPN":"とにかく殺しに行きゃいいんだろ？　うん？　おやじの仇を……！","ENG":"Anyway, we can go kill her now, right? Right? To avenge my father..!","TWN":"總之就先幹掉她再說吧！怎麼樣？我爸的仇……！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"정신 차려. 복수할 생각은 있는 건가?","JPN":"しっかりしろ。復讐するつもりはあるのか？","ENG":"Pull yourself together. Do you really want revenge?","TWN":"清醒一點，你是真的想報仇嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"저 상태로 죽이면 그걸로 끝이야.","JPN":"あのまま殺せばそれでおしまいだ。","ENG":"If you kill her, that’s it. It’s over.","TWN":"就那樣把她殺了未免太便宜她。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"막다른 골목에 밀어넣은 채로, 소중한 건 모조리 빼앗는다.","JPN":"行き止まりに追い込んで、大事なものはすべて奪う。","ENG":"Drive her into a corner, and take everything that is precious from her.","TWN":"我要把她逼到走投無路，再將她心愛的東西全都奪走。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"나는…… 저 녀석이 차라리 죽여 달라고 애원하는 꼴을 보고 말겠어.","JPN":"私は……あいつがいっそ殺してくれと泣きすがる様を見てやる。","ENG":"I... will see that bastard begging me to kill her.","TWN":"我要她……哀求我殺了她。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤…….","JPN":"へ、へへ……","ENG":"Heh, heh heh...","TWN":"嘿嘿嘿……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그거 알아, 나리? 나리는 새파랗게 어려 보이는 주제에 엄청 늙은이 같다니까?","JPN":"知ってるか？　旦那は若く見えるくせに、めっちゃくちゃ年寄りっぽいんだ。","ENG":"You know what? You look young, but you got an old heart.","TWN":"姊，你知道嗎？姊外表看起來很年輕，但思想和說話方式滿老派的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……그렇겠지. 동면 조치를 받고 냉동된 신세였으니까.","JPN":"……そうだろうな。冬眠処置で冷凍されてた身だったから。","ENG":"...I guess so. I was frozen in cryostasis after all.","TWN":"……這是當然，我可是受過冬眠處理的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"오빠가 죽은 뒤로 웃지도, 울지도 못하게 됐어.","JPN":"兄さんが死んだ後、笑うことも泣くこともできなくなった。","ENG":"After my brother died, I lost the ability to laugh or cry.","TWN":"自從我哥死掉後，我便再也笑不出來，也哭不出來。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"인간 흉내를 내고 있는 지금의 너는 어떨까, 마에스트로.","JPN":"人間のふりをしている今のあなたはどうだろうか、マエストロ。","ENG":"What about you, Maestra, who is just pretending to be human?","TWN":"模仿人類的你會怎麼樣呢，指揮家？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"가증스럽게 슬퍼할까? 아니면 그 때처럼 벌레 한 마리 죽은 셈 칠까?","JPN":"憎たらしく悲しむだろうか。それともあの時のように虫が一匹死んだと思うのだろうか。","ENG":"Shall you mourn? Or shall you shrug as if you had just stepped on a bug?","TWN":"你會痛不欲生嗎？還是跟當初一樣，感覺就只是捏死一隻蟲子？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……첫 번째는 너다. 마음껏 원망해.","JPN":"……最初はあなただ。存分に恨め。","ENG":"...You’re the first one I’ll kill. Hate me all you like.","TWN":"……就從你開始，儘管恨我吧。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤! 좋아! 다른 놈들이야 나리 맘대로 해치우라고! 나는 저 여자만……!","JPN":"へ、へへ！　よし！　他の奴らは旦那の好きなようにやっつけろ！　俺はあの女だけ……！","ENG":"Hey! Nice. It’s those other guys. You can do whatever you want with them, only the girl is what I...!","TWN":"嘿嘿嘿！沒問題！姊要殺誰我都沒意見！我只要那女人……！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"어? 아무도 안 쓰러졌는데, 나리? 방금 쏜 거 아니었어?","JPN":"え？　誰も倒れてないぜ、旦那。今撃たなかったか？","ENG":"Eh? But no one’s falling down! Didn’t you just shoot?","TWN":"嗯？怎麼都沒人倒下？姊剛才不是有開槍嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……실패했어. 방해꾼들이 달라붙었거든.","JPN":"……失敗した。邪魔者が来た。","ENG":"...I missed. Some troublemakers have interfered.","TWN":"……沒打中，殺出程咬金。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"악보가 넘어간 시점에서 이용 가치가 사라졌다는 건가?","JPN":"楽譜が渡された時点で利用価値が無くなったということか？","ENG":"Did my value disappear once the score was handed over?","TWN":"樂譜拿到手後，我就失去利用價值了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아하, 이해가 빠른걸. 카르데나스 부전대장님.","JPN":"まあ、呑み込みが早いわね。カルデナス副戦隊長。","ENG":"Aha, you pick up on things quickly, Cardenas Deputy Commander.","TWN":"哈哈，聰明喔，卡特納斯副戰隊長。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"셰나…….","JPN":"シェナ……","ENG":"Shena…","TWN":"世娜……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"최고 지휘자님을 다시 만나고 싶은 건 피차 마찬가지야.","JPN":"マエストロに再び会いたいのはこっちも同じよ。","ENG":"I too, want to meet the Chief Conductor.","TWN":"我和你一樣都很想見到首席指揮家，"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇지만 지휘자님을 죽이고 싶어서 환장한 애를 내버려 둘 수는 없잖니?","JPN":"だけど、マエストロを殺したくてしょうがない子を放っておくわけにもいかないじゃない？","ENG":"But as you are so eager to kill the Chief Conductor, I can’t just leave you alone now, can I?","TWN":"話雖如此，但也不能放任想殺死指揮家的瘋子不管的嘛～"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"따라서 예하와 멀리 떨어져 있을 때 처리한다. 으흠.","JPN":"だから猊下と離れているうちに処理する。えへん。","ENG":"Therefore I’ll take care of it when Eminence is far away. Ahem.","TWN":"所以才等到你和主教分開時再處理，咳咳。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……직접 행차하지도 않고, 가아그셰블라의 잔재들만으로 날 어떻게 해 볼 셈인가?","JPN":"……直接お出ましになる訳でもなく、ガアグシェブラの残滓だけで私とどう戦うつもり？","ENG":"...Not even taking care of it yourself, just leaving the remnants of Gha’agsheblah to do the job?","TWN":"……你沒親自現身，光憑加瓦格舍夫拉的碎片就想對付我？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜? 안 돼?","JPN":"何よ？　いけない？","ENG":"Why not?","TWN":"怎麼樣？不行嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 몸상태에는 그것들도 과한 것 같은데. 굳이 예하를 끌어들인 이유가 뭐겠어.","JPN":"その体の状態じゃあ、それも過ぎたことだと思うわ。あえて猊下を巻き込んだのもそれが理由でしょ？","ENG":"You are no match for them in your current condition. That’s why you involved Eminence.","TWN":"以你的身體狀態，那些東西對付你根本綽綽有餘，想也知道為什麼你非得把主教也拉進來。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"물러나, 폭주족! 4종 침식체에게도 유효타인 포격이야!","JPN":"下がれ、暴走族！　第4種侵食体にも効く砲撃だ！","ENG":"Get back! The artillery blast is effective even to a Category 4 Corrupted Object!","TWN":"退下，暴走族！這的火力可是足以對付4類侵蝕體！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐? 하늘에서 뚝 떨어진 것도 아닌데 그런 무기가 우리나라에 있을 리가……!","JPN":"は？　空から落ちたわけでもないし、そんな武器がこの国にあるわけ……！","ENG":"What? Where did such a weapon come from? No way it’s from our country, did it just fall out of the sky or something...?","TWN":"什麼？這是從天上掉下來的嗎？我們國家怎麼可能有這種武器……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 저런 괴물은 예전부터 있었어? 허튼 소리 말고 뛰어!","JPN":"それじゃあ、あんな化け物は昔からいたとでも言うの？　いいから走って！","ENG":"No way that monster could have come from your country. Anyways, stop talking and... Run!","TWN":"那從以前就有那個怪物嗎？廢話少說，快跑！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"입자포! 최대 출력으로 발사합니다!!","JPN":"粒子砲！　最大出力で発射します！！","ENG":"Particle gun! Fire at full power!","TWN":"粒子砲！以最大火力發射！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_ARONDIGHT_SKILL_LOOP"},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……음?","JPN":"……うむ？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"설마 시작하자마자 끝이야? 부전대장이라는 이름이 울겠는걸?","JPN":"まさか始まってすぐ終わり？　副戦隊長の名が泣くわね。","ENG":"Aww, don’t tell me it’s over as soon as it starts. Is little Deputy Commander going to cry?","TWN":"我才剛要開始欸？這麼快就結束啦？你這樣不會太愧對副戰隊長這個稱呼嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 기운을 차릴 수 있게 오빠 얘기라도 해 줄까.","JPN":"ふうん、元気出せるようにお兄さんの話でもしてあげようか。","ENG":"Hmm... How about I tell you something about your dear brother to cheer you up?","TWN":"嗯，還是要我提到你哥，這樣你才會振作一點嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"닥쳐!","JPN":"黙れ！","ENG":"Shut up!","TWN":"不准你提起我哥！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나리! 정부군 놈들한테 기습이라도 당한 거야?!","JPN":"旦那！　政府軍の野郎に不意打ちでもされてるのか！？","ENG":"Hey! Were you attacked by government soldiers?","TWN":"姊！是政府軍偷襲你嗎？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"지금 도우러 갈게! 기다려!","JPN":"今助けに行く！　待ってろ！","ENG":"I’ll be right there! Hold on!","TWN":"我們立刻過去幫你，你撐住！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"참견하지 말고 부하들이나 수습해, 멍청아!!","JPN":"出しゃばってないで手下をどうにかしろ、アホ！！","ENG":"Mind your own business, and take care of your men or something, idiot!","TWN":"少管閒事！快帶手下離開，你這個傻瓜！！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"세상에, 이용하고 버릴 생각이었던 인간들도 잘 챙겨 주는구나. 약해 빠진 주제에.","JPN":"まあ、利用した後に捨てる気だった人間もちゃんと面倒を見てあげるのね。弱虫のくせに。","ENG":"Oh my... You take such good care of the humans you are meant to use and throw away. Despite being so weak.","TWN":"這麼感人～你原本利用完就想扔的人，現在還想要來救你呢，而且他自己明明就很弱。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"잘 가, 부전대장님. 처음 봤을 때부터 느꼈지만 넌 역시 죽는 편이 제일 나아.","JPN":"さようなら、副戦隊長。初めて見た時からそう思ったけど、やっぱりあなたは死んだ方がいいわ。","ENG":"Bye bye, little Deputy Commander. I knew it right from when I first met you, but the best thing for you to do is die.","TWN":"安心上路吧， 副戰隊長。打從我第一次見到你就有這種感覺，死亡才是最適合你的。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>지</color>식을 완<color=#ff3636>성하</color>라.","JPN":"<color=#ff3636>知</color>識を完<color=#ff3636>成させ</color>ろ。","ENG":"<color=#ff3636>Com</color>plete Know<color=#ff3636>ledge</color>.","TWN":"完成<color=#ff3636>知</color><color=#ff3636>識</color>。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"폭<color=#ff3636>발하는 별</color>무리의 문으로부터 오롯이 존재하는 분<color=#ff3636>이 찬미</color>를 딛고 오리니.","JPN":"爆<color=#ff3636>発する星</color>群の門から完全体として存在される方<color=#ff3636>が賛美</color>と共に来たれり。","ENG":"From the doorstep of <color=#ff3636>exploding st</color>ars, the perfect existence, us<color=#ff3636>ing the steps of exaltations sh</color>all come.","TWN":"孤寂存在之人從爆<color=#ff3636>炸的群星</color>之門，踏著<color=#ff3636>讚美</color>而來。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"제기랄…….","JPN":"クソ……","ENG":"Damn it...","TWN":"該死的……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"가아그셰블라의 잔재들……. 일전에 처치한 것으로 끝이 아니었던가.","JPN":"ガアグシェブラの残滓……この前片付けたもので終わりではなかったのか。","ENG":"Gha’agsheblah’s remnants... I thought we dealt with them already.","TWN":"加瓦格舍夫拉的碎片……之前處理掉後還沒結束嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 대지에도 이미 깊이 뿌리를 내린 모양이군.","JPN":"この大地にもすでに深く根を降ろしているようだ。","ENG":"They already have deep roots in this land.","TWN":"看來在這片土地上也種下很深的根呢。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"모르스……?","JPN":"モールス……？","ENG":"Mors...?","TWN":"莫爾斯……？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"물러서서 몸을 추슬러라. 나는 저들에게 안식을 선사하마.","JPN":"退き、体調を回復しろ。我はあの者たちに安息を与えてやろう。","ENG":"Stand back and take repose. I shall give them rest.","TWN":"你去恢復一下吧，我會讓她們進入安息。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마에스트로는? 설마 눈앞에 있는데 어째서 포기한 거야?","JPN":"マエストロは？　まさか、目の前に居たのにあきらめた？","ENG":"What about Maestra? She’s right in front of you, why would you give up?","TWN":"那指揮家呢？她現在就近在眼前，難道你要我放棄嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"놈이 공포를 느끼게 만들어야 할 거 아냐! 어정쩡하게 끝내면 무슨 의미가 있어!","JPN":"奴に恐怖を味わわせなければ！　中途半端に終わらせて何の意味があるんだ！","ENG":"You had to terrorize her! What’s the point of only going this far?","TWN":"我要讓她感受到恐懼！要是就這樣不明不白地結束，那還有什麼意義！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_ESPR_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"미니스트라에 대해 언급한 것은 너였다. 몽타뉴.","JPN":"ミニストラについて口にしたのはそなただった。モンターニュ。","ENG":"It was you who mentioned Ministra. Montagne.","TWN":"蒙塔妮，是你提到迷你斯特拉的。"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_ESPR_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？你說什麼？"},"stage":{"bg":"SS_SHADOW_06","bgm":"THEMA_ESPR_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이번에는, 늦지 않았다.","JPN":"今度は、遅れていない。","ENG":"This time, it is not too late.","TWN":"這次，我不會再慢一步。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};